class Solution:
    def check_bit(self, s: str, index: int) -> bool:
        left = 0
        right = index
        while left <= right:
            if s[index - right + left] == '0':
                return False
            left += 1
        return True

    def min_count_binary_substrings(self, s: str) -> int:
        count = 0
        prev = 1
        for i in range(1, len(s)):
            if s[i] == '0' or s[i - 1] == '0':
                prev = 0
            else:
                prev += 1
            count += prev
        return count


# main function
def main():
    solution = Solution()
    s = input()
    result = solution.min_count_binary_substrings(s)
    print(result)

if __name__ == '__main__':
    main()

