class Solution { public:
bool checkBit(const string& s, int index) {
    int left = 0, right = index;
    while (left <= right) {
        if (s[index - right + left] == '0')
            return false;
        left++;
    }
    return true;
}
int minCountBinarySubstrings(string s) {
    int count = 0, prev = 1;
    for (int i = 1; i < s.size(); i++)
        if (s[i] == '0' || s[i - 1] == '0')
            prev = 0;
        else
            prev++;
        count += prev;
    return count;
}
};
int main() {
    string s;
    getline(cin, s);
    Solution solution;
    cout << solution.minCountBinarySubstrings(s) << endl;
    return 0;
}
